func:
const d = msg.data || {};
const rp = msg._resolvedProvider || {};
const apiKey = rp.apiKey || flow.get("openai_api_key") || "";
const model  = rp.model || flow.get("openai_model") || "gpt-4o";

if (!apiKey) {
    msg.response = { action:"enhancePrompt", status:"error", message:"No OpenAI API key configured. Set OPENAI_API_KEY on the flow." };
    return [null, msg];            // output 2 → error path
}

msg.url = rp.apiEndpoint || "https://api.openai.com/v1/chat/completions";
if (rp.type === 'anthropic') {
    msg.headers = {
        "Content-Type": "application/json",
        "x-api-key": apiKey,
        "anthropic-version": "2023-06-01"
    };
} else {
    msg.headers = {
        "Content-Type":  "application/json",
        "Authorization": "Bearer " + apiKey
    };
}
msg.payload = {
    model: model,
    temperature: 0.3,
    max_tokens: 4096,
    messages: [
        {
            role: "system",
            content: "You are an expert at writing LLM transformation prompts for schema-to-schema data conversion. Given a user's rough prompt, improve it to be clearer, more specific, and more effective. Keep the user's original intent. Return ONLY the improved prompt text, nothing else."
        },
        {
            role: "user",
            content: (() => {
                // FR-SR-04: Resolve template variables before sending to LLM
                let tplText = (d.rawPrompt || d.template || d.originalPrompt || "");
                tplText = tplText.replace(/\{SOURCE_SCHEMA\}/g, d.sourceSchema || "");
                tplText = tplText.replace(/\{TARGET_SCHEMA\}/g, d.targetSchema || "");
                tplText = tplText.replace(/\{EXAMPLES\}/g, d.examples || "");
                tplText = tplText.replace(/\{CONSTRAINTS\}/g, d.constraints || "");
                return "Source schema: " + (d.sourceSchema || "") +
                       "\nTarget schema: " + (d.targetSchema || "") +
                       "\n\nSchema context:\n" + (d.schemaContext || "(none)") +
                       "\n\nUser's raw prompt:\n" + tplText +
                       "\n\nReturn the improved prompt only.";
            })()
        }
    ]
};

return [msg, null];               // output 1 → http request

const body = msg.payload || {};
const content = (body.choices && body.choices[0] && body.choices[0].message && body.choices[0].message.content) || "";

msg.response = {
    action: "enhancePrompt",
    status: "success",
    enhancedPrompt: content.trim()
};
delete msg.payload;
delete msg.headers;
delete msg.url;
return msg;

const status = msg.statusCode || 0;
const body   = msg.payload || {};
const errMsg = (body.error && body.error.message) || JSON.stringify(body);

msg.response = {
    action: "enhancePrompt",
    status: "error",
    message: "OpenAI returned HTTP " + status + ": " + errMsg
};
delete msg.payload;
delete msg.headers;
delete msg.url;
return msg;

const d = msg.data || {};

// generate unique id
const chars = 'abcdefghijklmnopqrstuvwxyz0123456789';
let rnd = '';
for (let i = 0; i < 8; i++) rnd += chars[Math.floor(Math.random() * chars.length)];
const id  = 'prompt-' + Date.now().toString(36) + rnd;
const now = new Date().toISOString().slice(0, 10);

const prompt = {
    id:                   id,
    version:              d.version || "1.0",
    status:               "writing code",
    sourceSchema:         d.sourceSchema || "",
    targetSchema:         d.targetSchema || "",
    template:             d.template || "",
    examples:             d.examples || "",
    constraints:          d.constraints || "",
    providerId:           d.providerId || "",
    originalPrompt:       d.template || "",
    enhancedPrompt:       d.enhancedPrompt || "",
    generatedCode:        "",
    codeGenerationStatus: "generating",
    createdAt:            now,
    updatedAt:            now,
    lastGeneratedAt:      "",
    // FR-CR-03 kind discriminator (default schema-mapping; api-mapping when caller sets msg.data.kind)
    kind:                 (d.kind === "api-mapping") ? "api-mapping" : "schema-mapping",
    targetCatalogueId:    (d.kind === "api-mapping") ? (d.targetCatalogueId || "") : ""
};

msg._promptData = prompt;
msg.collection  = "sr_prompts";
msg.operation   = "insertOne";
msg.payload     = prompt;
return msg;

const p = msg._promptData || {};
const now = new Date().toISOString();
msg._promptResponse = {
    action: "createPrompt",
    status: "success",
    prompt: p
};
msg.collection = 'dcm_audit_log';
msg.operation = 'insertOne';
msg.payload = {
    timestamp: now,
    actor: msg._callerUsername || msg.auth?.username || 'system',
    area: 'prompt',
    action: 'prompt.created',
    target: p.id,
    after: { sourceSchema: p.sourceSchema, targetSchema: p.targetSchema, version: p.version },
    result: 'success'
};
return msg;

const p      = msg._promptData || {};
const rp     = msg._resolvedProvider || {};
const apiKey = rp.apiKey || flow.get("openai_api_key") || "";
const model  = rp.model || flow.get("openai_model") || "gpt-4o";

if (!apiKey) {
    // No API key → cannot generate code. Mark as error.
    msg._codeGenError = "No OpenAI API key configured.";
    msg._generatedCode = "";
    return [null, msg];   // output 2 → skip to update-with-error
}

msg.url = rp.apiEndpoint || "https://api.openai.com/v1/chat/completions";
if (rp.type === 'anthropic') {
    msg.headers = {
        "Content-Type": "application/json",
        "x-api-key": apiKey,
        "anthropic-version": "2023-06-01"
    };
} else {
    msg.headers = {
        "Content-Type":  "application/json",
        "Authorization": "Bearer " + apiKey
    };
}
msg.payload = {
    model: model,
    temperature: 0.3,
    max_tokens: 4096,
    messages: [
        {
            role: "system",
            content: "You are a code generator. Output ONLY a single JavaScript function named `transform` that takes one argument `input` (a plain object) and returns the transformed object. No markdown fences, no explanation, no imports. The function must be deterministic, handle missing fields gracefully, and produce valid JSON-serialisable output."
        },
        {
            role: "user",
            content: (() => {
                // FR-SR-04: Resolve template variables before sending to LLM
                let resolved = (p.template || "");
                resolved = resolved.replace(/\{SOURCE_SCHEMA\}/g, p.sourceSchema || "");
                resolved = resolved.replace(/\{TARGET_SCHEMA\}/g, p.targetSchema || "");
                resolved = resolved.replace(/\{EXAMPLES\}/g, p.examples || "");
                resolved = resolved.replace(/\{CONSTRAINTS\}/g, p.constraints || "");
                // {SOURCE_ASSET} is not available at code-gen time, leave as placeholder
                // The generated code will receive the actual asset as `input` parameter
                return "Source schema: " + (p.sourceSchema || "") +
                       "\nTarget schema: " + (p.targetSchema || "") +
                       "\n\nPrompt / mapping instructions:\n" + resolved +
                       "\n\nExamples:\n" + (p.examples || "(none)") +
                       "\n\nConstraints:\n" + (p.constraints || "(none)") +
                       "\n\nGenerate the JavaScript transform function now.";
            })()
        }
    ]
};

return [msg, null];      // output 1 → http request

const body = msg.payload || {};
let code = (body.choices && body.choices[0] && body.choices[0].message && body.choices[0].message.content) || "";

// Strip markdown fences if present
code = code.replace(/^```(?:javascript|js)?\s*\n?/i, "")
           .replace(/\n?```\s*$/i, "")
           .trim();

msg._generatedCode = code;
msg._codeGenError  = null;
return msg;

const status = msg.statusCode || 0;
const body   = msg.payload || {};
const errMsg = (body.error && body.error.message) || JSON.stringify(body);

msg._generatedCode = "";
msg._codeGenError  = "OpenAI HTTP " + status + ": " + errMsg;
return msg;

const p   = msg._promptData || {};
const now = new Date().toISOString().slice(0, 10);
const hasCode = !!msg._generatedCode;

msg.collection = "sr_prompts";
msg.operation  = "updateOne";
msg.payload = [
    { id: p.id },
    { $set: {
        generatedCode:        msg._generatedCode || "",
        codeGenerationStatus: hasCode ? "completed" : "error",
        status:               hasCode ? "active"    : "error",
        lastGeneratedAt:      hasCode ? now : "",
        updatedAt:            now
    }}
];
return msg;

const p       = msg._promptData || {};
const now     = new Date().toISOString().slice(0, 10);
const hasCode = !!msg._generatedCode;

msg.response = {
    action:         "codeGenerated",
    status:         hasCode ? "success" : "error",
    promptId:       p.id,
    generatedCode:  msg._generatedCode || "",
    lastGeneratedAt: hasCode ? now : "",
    updatedAt:      now,
    message:        msg._codeGenError || ""
};

delete msg._promptData;
delete msg._generatedCode;
delete msg._codeGenError;
delete msg.payload;
delete msg.collection;
delete msg.operation;
return msg;

msg.collection = "sr_prompts";
msg.operation  = "find";
// FR-CR-03: optional kind filter (schema-mapping default)
const _kind = (msg.data && msg.data.kind) ? msg.data.kind : null;
const _filter = _kind ? { kind: _kind } : {};
msg.payload    = [_filter, { projection: { _id: 0 } }];
return msg;

msg.response = {
    action:  "listPrompts",
    status:  "success",
    prompts: Array.isArray(msg.payload) ? msg.payload : [],
    // FR-CR-03: echo requested kind so the UI can route the response
    kind:    (msg.data && msg.data.kind) ? msg.data.kind : null
};
delete msg.payload;
delete msg.collection;
delete msg.operation;
return msg;

const d   = msg.data || {};
const now = new Date().toISOString().slice(0, 10);
msg._promptId  = d.promptId;
msg._savedCode = d.code || "";
msg.collection = "sr_prompts";
msg.operation  = "updateOne";
msg.payload    = [
    { id: d.promptId },
    { $set: { generatedCode: d.code || "", updatedAt: now } }
];
return msg;

msg.response = {
    action:    "updatePromptCode",
    status:    "success",
    promptId:  msg._promptId,
    code:      msg._savedCode,
    updatedAt: new Date().toISOString().slice(0, 10)
};
delete msg._promptId;
delete msg._savedCode;
delete msg.payload;
delete msg.collection;
delete msg.operation;
return msg;

const d = msg.data || {};
msg._promptId  = d.promptId;
msg._promptBefore = null;
msg.collection = "sr_prompts";
msg.operation  = "findOne";
msg.payload    = { id: d.promptId };
return msg;

const now = new Date().toISOString();
msg._promptResponse = {
    action: "deletePrompt",
    status: "success",
    promptId: msg._promptId
};
msg.collection = 'dcm_audit_log';
msg.operation = 'insertOne';
msg.payload = {
    timestamp: now,
    actor: msg._callerUsername || msg.auth?.username || 'system',
    area: 'prompt',
    action: 'prompt.deleted',
    target: msg._promptId,
    before: msg._promptBefore || null,
    result: 'success'
};
delete msg._promptId;
return msg;

const d = msg.data || {};
msg._dryRunData = d;
msg.collection  = "sr_prompts";
msg.operation   = "findOne";
msg.payload     = { id: d.promptId };
return msg;

const d      = msg._dryRunData || {};
const prompt = msg.payload;

if (!prompt) {
    msg.response = { action:"dryRunPrompt", status:"error", message:"Prompt not found" };
    delete msg.payload;
    return msg;
}

const code = prompt.generatedCode || "";
if (!code) {
    msg.response = { action:"dryRunPrompt", status:"error", message:"No generated code for this prompt" };
    delete msg.payload;
    return msg;
}

// Parse sample input
let input;
try {
    input = JSON.parse(d.sampleInput || "{}");
} catch (e) {
    input = d.sampleInput;
}

// Execute the saved/edited transformation function
try {
    const fn     = new Function("input", code + "\nreturn transform(input);");
    const result = fn(input);
    // FR-SR-04: Resolve template for display
    let resolvedTpl = (prompt.template || "");
    resolvedTpl = resolvedTpl.replace(/\{SOURCE_ASSET\}/g, JSON.stringify(input).substring(0, 500));
    resolvedTpl = resolvedTpl.replace(/\{SOURCE_SCHEMA\}/g, prompt.sourceSchema || "");
    resolvedTpl = resolvedTpl.replace(/\{TARGET_SCHEMA\}/g, prompt.targetSchema || "");
    resolvedTpl = resolvedTpl.replace(/\{EXAMPLES\}/g, prompt.examples || "");
    resolvedTpl = resolvedTpl.replace(/\{CONSTRAINTS\}/g, prompt.constraints || "");
    msg.response = {
        action:   "dryRunPrompt",
        status:   "success",
        result:   JSON.stringify(result, null, 2),
        promptId: d.promptId,
        resolvedPrompt: resolvedTpl
    };
} catch (execErr) {
    msg.response = {
        action:   "dryRunPrompt",
        status:   "error",
        message:  "Code execution failed: " + execErr.message,
        promptId: d.promptId
    };
}

delete msg._dryRunData;
delete msg.payload;
delete msg.collection;
delete msg.operation;
return msg;

const d   = msg.data || {};
const now = new Date().toISOString().slice(0, 10);

if (d.id) {
    // Update existing
    msg._testCaseId = d.id;
    var tc = {
        id:             d.id,
        name:           d.name || "",
        promptId:       d.promptId || "",
        llmConfigId:    d.llmConfigId || "",
        sampleInput:    d.sampleInput || "",
        expectedOutput: d.expectedOutput || "",
        updatedAt:      now
    };
    msg._testCaseData = tc;
    msg.collection  = "sr_test_cases";
    msg.operation   = "updateOne";
    msg.payload = [
        { id: d.id },
        { $set: {
            name:           tc.name,
            promptId:       tc.promptId,
            llmConfigId:    tc.llmConfigId,
            sampleInput:    tc.sampleInput,
            expectedOutput: tc.expectedOutput,
            updatedAt:      now
        }}
    ];
} else {
    // Insert new
    const chars = 'abcdefghijklmnopqrstuvwxyz0123456789';
    let rnd = '';
    for (let i = 0; i < 6; i++) rnd += chars[Math.floor(Math.random() * chars.length)];
    const id = 'tc-' + rnd;
    msg._testCaseId = id;
    msg._isNew      = true;
    var newTc = {
        id:             id,
        name:           d.name || "",
        promptId:       d.promptId || "",
        llmConfigId:    d.llmConfigId || "",
        sampleInput:    d.sampleInput || "",
        expectedOutput: d.expectedOutput || "",
        lastResult:     "",
        lastRunAt:      "",
        createdAt:      now,
        updatedAt:      now
    };
    msg._testCaseData = newTc;
    msg.collection   = "sr_test_cases";
    msg.operation    = "insertOne";
    msg.payload      = newTc;
}
return msg;

msg.response = {
    action:     "saveTestCase",
    status:     "success",
    testCaseId: msg._testCaseId,
    isNew:      !!msg._isNew,
    testCase:   msg._testCaseData || null
};
delete msg._testCaseId;
delete msg._isNew;
delete msg._testCaseData;
delete msg.payload;
delete msg.collection;
delete msg.operation;
return msg;

msg.collection = "sr_test_cases";
msg.operation  = "find";
msg.payload    = [{}, { projection: { _id: 0 } }];
return msg;

msg.response = {
    action:    "listTestCases",
    status:    "success",
    testCases: Array.isArray(msg.payload) ? msg.payload : []
};
delete msg.payload;
delete msg.collection;
delete msg.operation;
return msg;

const d = msg.data || {};
msg._testCaseId = d.testCaseId;
msg.collection  = "sr_test_cases";
msg.operation   = "deleteOne";
msg.payload     = { id: d.testCaseId };
return msg;

msg.response = {
    action:     "deleteTestCase",
    status:     "success",
    testCaseId: msg._testCaseId
};
delete msg._testCaseId;
delete msg.payload;
delete msg.collection;
delete msg.operation;
return msg;

const d = msg.data || {};
msg._updateOriginalData = d;
msg._promptId = d.promptId;

if (d.status === "active") {
    msg.collection = "sr_prompts";
    msg.operation  = "findOne";
    msg.payload    = {
        status: "active",
        sourceSchema: d.sourceSchema,
        targetSchema: d.targetSchema,
        id: { $ne: d.promptId }
    };
    return [msg, null];  // output 1 → conflict check
}
return [null, msg];      // output 2 → skip to update

const conflict = msg.payload;
if (conflict) {
    const cid = conflict.id || "unknown";
    msg.response = {
        action: "updatePrompt",
        status: "error",
        message: 'Only one active prompt allowed per source-target pair. "' + cid + '" is already active.'
    };
    delete msg.payload;
    delete msg.collection;
    delete msg.operation;
    return [null, msg];  // output 2 → error response
}
msg.data = msg._updateOriginalData;
delete msg._updateOriginalData;
return [msg, null];      // output 1 → proceed to update

const d   = msg.data || {};
const now = new Date().toISOString().slice(0, 10);
msg._promptId   = d.promptId;
msg._updateData = d;
msg.collection  = "sr_prompts";
msg.operation   = "updateOne";

const update = {};
if (d.version      !== undefined) update.version      = d.version;
if (d.sourceSchema !== undefined) update.sourceSchema = d.sourceSchema;
if (d.targetSchema !== undefined) update.targetSchema = d.targetSchema;
if (d.template     !== undefined) update.template     = d.template;
if (d.examples     !== undefined) update.examples     = d.examples;
if (d.constraints  !== undefined) update.constraints  = d.constraints;
if (d.providerId   !== undefined) update.providerId   = d.providerId;
if (d.status       !== undefined) update.status       = d.status;
if (d.code         !== undefined) update.generatedCode = d.code;
update.updatedAt = now;

msg.payload = [
    { id: d.promptId },
    { $set: update }
];
return msg;

var d = msg._updateData || {};
var now = new Date().toISOString();
msg._promptResponse = {
    action:       "updatePrompt",
    status:       "success",
    promptId:     msg._promptId,
    version:      d.version,
    sourceSchema: d.sourceSchema,
    targetSchema: d.targetSchema,
    template:     d.template,
    examples:     d.examples,
    constraints:  d.constraints,
    promptStatus: d.status,
    code:         d.code,
    updatedAt:    now.slice(0, 10)
};
msg.collection = 'dcm_audit_log';
msg.operation = 'insertOne';
msg.payload = {
    timestamp: now,
    actor: msg._callerUsername || msg.auth?.username || 'system',
    area: 'prompt',
    action: 'prompt.updated',
    target: msg._promptId,
    after: { version: d.version, sourceSchema: d.sourceSchema, targetSchema: d.targetSchema },
    result: 'success'
};
delete msg._promptId;
delete msg._updateData;
return msg;

const d = msg.data || {};
msg._statusOriginalData = d;
msg._promptId   = d.promptId;
msg._newStatus  = d.status;

if (d.status === "active") {
    msg.collection = "sr_prompts";
    msg.operation  = "findOne";
    msg.payload    = {
        status: "active",
        sourceSchema: d.sourceSchema,
        targetSchema: d.targetSchema,
        id: { $ne: d.promptId }
    };
    return [msg, null];  // output 1 → conflict check
}
return [null, msg];      // output 2 → skip to update

const conflict = msg.payload;
if (conflict) {
    const cid = conflict.id || "unknown";
    msg.response = {
        action: "updatePromptStatus",
        status: "error",
        message: 'Cannot activate: "' + cid + '" is already active for this source-target pair.'
    };
    delete msg.payload;
    delete msg.collection;
    delete msg.operation;
    return [null, msg];  // output 2 → error response
}
msg.data = msg._statusOriginalData;
delete msg._statusOriginalData;
return [msg, null];      // output 1 → proceed to update

const d   = msg.data || {};
const now = new Date().toISOString().slice(0, 10);
msg._promptId    = d.promptId;
msg._newStatus   = d.status;
msg.collection   = "sr_prompts";
msg.operation    = "updateOne";
msg.payload = [
    { id: d.promptId },
    { $set: { status: d.status, updatedAt: now } }
];
return msg;

var now = new Date().toISOString();
var auditAction = 'prompt.status_changed';
if (msg._newStatus === 'active') auditAction = 'prompt.activated';
else if (msg._newStatus === 'deprecated') auditAction = 'prompt.deprecated';
msg._promptResponse = {
    action:    "updatePromptStatus",
    status:    "success",
    promptId:  msg._promptId,
    newStatus: msg._newStatus,
    updatedAt: now.slice(0, 10)
};
msg.collection = 'dcm_audit_log';
msg.operation = 'insertOne';
msg.payload = {
    timestamp: now,
    actor: msg._callerUsername || msg.auth?.username || 'system',
    area: 'prompt',
    action: auditAction,
    target: msg._promptId,
    after: { status: msg._newStatus },
    result: 'success'
};
delete msg._promptId;
delete msg._newStatus;
return msg;

const d   = msg.data || {};
const now = new Date().toISOString().slice(0, 10);

if (d.id) {
    msg._configId = d.id;
    msg._isNew    = false;
    msg._configData = d;
    msg.collection  = "sr_llm_configs";
    msg.operation   = "updateOne";
    msg.payload = [
        { id: d.id },
        { $set: {
            name:        d.name || "",
            provider:    d.provider || "OpenAI",
            model:       d.model || "",
            temperature: d.temperature ?? 0.3,
            maxTokens:   d.maxTokens ?? 4096,
            timeout:     d.timeout ?? 30,
            status:      d.status || "active",
            updatedAt:   now
        }}
    ];
} else {
    const chars = 'abcdefghijklmnopqrstuvwxyz0123456789';
    let rnd = '';
    for (let i = 0; i < 6; i++) rnd += chars[Math.floor(Math.random() * chars.length)];
    const id = 'llm-' + rnd;
    msg._configId = id;
    msg._isNew    = true;
    const config = {
        id:          id,
        name:        d.name || "",
        provider:    d.provider || "OpenAI",
        model:       d.model || "",
        temperature: d.temperature ?? 0.3,
        maxTokens:   d.maxTokens ?? 4096,
        timeout:     d.timeout ?? 30,
        status:      d.status || "active",
        createdAt:   now,
        updatedAt:   now
    };
    msg._configData = config;
    msg.collection  = "sr_llm_configs";
    msg.operation   = "insertOne";
    msg.payload     = config;
}
return msg;

const d   = msg._configData || {};
const now = new Date().toISOString().slice(0, 10);
const config = {
    id:          msg._configId,
    name:        d.name || "",
    provider:    d.provider || "OpenAI",
    model:       d.model || "",
    temperature: d.temperature ?? 0.3,
    maxTokens:   d.maxTokens ?? 4096,
    timeout:     d.timeout ?? 30,
    status:      d.status || "active",
    createdAt:   d.createdAt || now,
    updatedAt:   now
};
msg.response = {
    action:   "saveLlmConfig",
    status:   "success",
    configId: msg._configId,
    isNew:    !!msg._isNew,
    config:   config
};
delete msg._configId;
delete msg._isNew;
delete msg._configData;
delete msg.payload;
delete msg.collection;
delete msg.operation;
return msg;

const d = msg.data || {};
msg._configId  = d.configId;
msg.collection = "sr_llm_configs";
msg.operation  = "deleteOne";
msg.payload    = { id: d.configId };
return msg;

msg.response = {
    action:   "deleteLlmConfig",
    status:   "success",
    configId: msg._configId
};
delete msg._configId;
delete msg.payload;
delete msg.collection;
delete msg.operation;
return msg;

const d   = msg.data || {};
const now = new Date().toISOString().slice(0, 10);
const models = Array.isArray(d.models) ? d.models : [];

// Defensive log so Debug sidebar always shows what we upserted.
node.warn('saveProvider prepare: id=' + (d.id || '(new)') +
          ' name=' + (d.name || '') +
          ' apiKey.type=' + (typeof d.apiKey) +
          ' apiKey.hasCt=' + !!(d.apiKey && d.apiKey.ct));

if (d.id) {
    msg._providerId   = d.id;
    msg._isNew        = false;
    msg._providerData = d;
    msg.collection    = 'sr_providers';
    msg.operation     = 'updateOne';
    const set = {
        name:        d.name || '',
        type:        d.type || 'openai',
