    if (processed > total * 0.6 && errorCount === 0) {
        errorCount = Math.ceil(total * 0.02);
        errors = [
            { assetId: "asset-err-001", message: "SHACL validation failed", timestamp: new Date().toISOString().slice(0, 19) },
            { assetId: "asset-err-002", message: "LLM timeout exceeded", timestamp: new Date().toISOString().slice(0, 19) }
