    }

    var update = {
        action: "batchRetransformProgress",
        status: processed >= total ? "completed" : "running",
        progress: progress,
        processedAssets: processed,
        totalAssets: total,
        successCount: processed - errorCount,
        errorCount: errorCount,
        skippedCount: 0,
        errors: errors,
        startedAt: startedAt,
        completedAt: processed >= total ? new Date().toISOString().replace("T", " ").slice(0, 16) : ""
    };

    if (processed >= total) {
        clearInterval(intervalId);
        flow.set("batchIntervalId", null);
        flow.set("batchState", { status: "completed" });
        var triggerLabels = { prompt_change: "Prompt changed", strategy_change: "Strategy changed", llm_change: "LLM config changed", manual: "Manual trigger" };
