            total: total,
            success: processed - errorCount,
            errors: errorCount,
            skipped: 0,
            startedAt: startedAt,
            completedAt: update.completedAt,
            status: "completed"
        };
    }

    var progressMsg = RED.util.cloneMessage(msg);
    progressMsg.response = update;
