    if (!token && msg.payload && typeof msg.payload === 'object') {
        if (msg.payload.token) token = msg.payload.token;
        else if (msg.payload.data && msg.payload.data.token) token = msg.payload.data.token;
        else if (msg.payload.auth && msg.payload.auth.userToken) token = msg.payload.auth.userToken;
        else if (msg.payload._token) token = msg.payload._token;
    }
    if (!token && msg._uib && msg._uib.token) token = msg._uib.token;

    // Parse token from topic (format: "route|TOKEN")
    if (!token && msg.topic && msg.topic.indexOf('|') !== -1) {
        const parts = msg.topic.split('|');
        if (parts.length === 2 && parts[1].length > 10) {
            token = parts[1];
        }
    }

    // Last resort: check flow context (cached from previous successful auth)
    if (!token) {
        const clientId = (msg._uib && msg._uib.clientId) || (msg._socketId) || '';
        if (clientId) {
            token = flow.get('authToken_' + clientId) || '';
            if (token) {
                node.warn('Auth Resolver: Token found in flow cache for client=' + clientId);
            }
        }
    }

    msg._originalType    = msg.type || '';
    msg._originalPayload = (msg.payload && typeof msg.payload === 'object') ? JSON.parse(JSON.stringify(msg.payload)) : msg.payload;
    msg._originalData    = msg.data ? JSON.parse(JSON.stringify(msg.data)) : undefined;
    msg._originalTopic   = msg.topic || '';

    if (!token) {
        msg.response = {
            action: msg.type || 'unknown',
            ok: false,
            code: 'not_authenticated',
            error: 'Not authenticated — no token'
        };
        const keys = Object.keys(msg).filter(k => !k.startsWith('_'));
        node.warn('Auth Resolver: No token found. Keys on msg: [' + keys.join(', ') + '] | msg.data=' + JSON.stringify(msg.data || null) + ' | msg._token=' + (msg._token || 'undefined') + ' | msg.topic=' + (msg.topic || 'undefined') + ' | msg.payload type=' + (typeof msg.payload) + ' keys=' + JSON.stringify(Object.keys(msg.payload || {})));
        return [null, null, msg];
    }

    const clientId = (msg._uib && msg._uib.clientId) || (msg._socketId) || '';
    if (clientId) {
        flow.set('authToken_' + clientId, token);
    }

    msg._authStep = 1;
    msg._sessionToken = token;
    msg.collection = 'auth_sessions';
    msg.operation = 'findOne';
    msg.payload = { token: token };
    return [msg, null, null];
}

// ── Step 1: Session result → look up user ──
if (step === 1) {
    const session = unwrap(msg.payload);

    if (!session) {
        msg.type = msg._originalType;
        msg.response = { action: msg._originalType, ok: false, code: 'not_authenticated', error: 'Session not found' };
        return [null, null, msg];
    }

    if (session.expiresAt && new Date(session.expiresAt) < new Date()) {
        msg.type = msg._originalType;
        msg.response = { action: msg._originalType, ok: false, code: 'not_authenticated', error: 'Session expired' };
        return [null, null, msg];
    }

    msg._authStep = 2;
    msg._callerUsername = session.username || (session.user && session.user.username) || '';
    msg._sessionData = session;
    msg.collection = 'dcm_users';
    msg.operation = 'findOne';
    msg.payload = { username: msg._callerUsername };
    return [msg, null, null];
}

// ── Step 2: User result → look up role ──
if (step === 2) {
    const user = unwrap(msg.payload);

    if (!user) {
        msg.type = msg._originalType;
        msg.response = { action: msg._originalType, ok: false, code: 'user_not_found', error: 'User "' + msg._callerUsername + '" not found in dcm_users' };
        return [null, null, msg];
    }

    msg._authStep = 3;
    msg._resolvedUser = user;

    let roleName = 'viewer';
    if (user.roles && Array.isArray(user.roles) && user.roles.length > 0) {
        roleName = user.roles[0];
    } else if (user.role && typeof user.role === 'string') {
        roleName = user.role;
    }
    if (user.username === 'admin' && roleName === 'viewer') {
        roleName = 'admin';
    }

    node.warn('Auth Resolver Step 2: user=' + user.username + ' role=' + roleName + ' user.roles=' + JSON.stringify(user.roles || null));

    msg.collection = 'dcm_roles';
    msg.operation = 'findOne';
    msg.payload = { name: roleName };
    return [msg, null, null];
}

// ── Step 3: Role result → build msg.auth → done ──
if (step === 3) {
    const role = unwrap(msg.payload);
    const user = msg._resolvedUser;

    let permissions = [];
    let roleName = 'viewer';

    if (role && role.permissions) {
        permissions = role.permissions;
        roleName = role.name;
    } else if (user.permissions && Array.isArray(user.permissions) && user.permissions.length > 0) {
        permissions = user.permissions;
        roleName = (user.roles && user.roles[0]) || user.role || 'viewer';
    }

    if (user.username === 'admin' && permissions.length === 0) {
        permissions = ['*'];
        roleName = 'admin';
        node.warn('Auth Resolver: Admin user had empty permissions — granting wildcard [*]');
    }

    msg.auth = {
        username:    user.username,
        userId:      String(user._id),
        userToken:   msg._sessionToken,
        role:        roleName,
        permissions: permissions,
        accessAreas: user.accessAreas || []
    };

    msg.type    = msg._originalType;
    msg.payload = msg._originalPayload;
    msg.data    = msg._originalData;
    msg.topic   = msg._originalTopic;
    msg._callerUsername = user.username || 'unknown';

    const clientId = (msg._uib && msg._uib.clientId) || (msg._socketId) || '';
    if (clientId && msg._sessionToken) {
        flow.set('authToken_' + clientId, msg._sessionToken);
    }

    delete msg._authStep;
    delete msg._originalType;
    delete msg._originalPayload;
    delete msg._originalData;
    delete msg._originalTopic;
    delete msg._sessionToken;
    delete msg._sessionData;
    delete msg._resolvedUser;
    delete msg.collection;
    delete msg.operation;

    node.warn('Auth Resolver: SUCCESS for user=' + msg.auth.username + ' role=' + msg.auth.role + ' perms=' + JSON.stringify(msg.auth.permissions) + ' action=' + msg.type);

    return [null, msg, null];
}

msg.response = { action: msg._originalType || 'unknown', ok: false, code: 'auth_error', error: 'Unknown auth step' };
return [null, null, msg];

// One-time migration: add schema.registry.* permissions to admin role(s).
// Safe to run repeatedly — $addToSet won't duplicate existing entries.
msg.collection = 'dcm_roles';
msg.operation  = 'updateMany';
msg.payload = [
    { $or: [ { name: 'admin' }, { name: 'Admin' }, { isSystemAdmin: true } ] },
    { $addToSet: { permissions: { $each: [
        'schema.registry.create',
        'schema.registry.read',
        'schema.registry.update',
        'schema.registry.delete',
        'catalogue.registry.create',
        'catalogue.registry.read',
        'catalogue.registry.update',
        'catalogue.registry.delete',
        'local.catalogue.read',
        'users.create',
        'users.read',
        'users.update',
        'users.delete',
        'roles.read',
        'audit.read',
        'harvest.create',
        'harvest.read',
        'harvest.update',
        'harvest.delete'
    ] } } }
];
return msg;

const r = msg.payload || {};
const modified = (r.modifiedCount != null) ? r.modifiedCount : (r.nModified || 0);
const matched = (r.matchedCount != null) ? r.matchedCount : (r.n || 0);
node.warn('[migration] admin role permissions: matched=' + matched + ', modified=' + modified);
return null;

const d = msg.data || {};
if (!d.mappingId) {
    msg.response = { action: 'saveRdfMappingConfig', success: false, error: 'Missing mappingId' };
    return [null, msg];
}
msg.collection = 'sr_mappings';
msg.operation  = 'updateOne';
msg.payload = [
    { id: d.mappingId },
    { $set: {
        namespacesToPreserve: Array.isArray(d.namespacesToPreserve) ? d.namespacesToPreserve : [],
        shaclShapeSchemaId:   d.shaclShapeSchemaId || '',
        updatedAt:            new Date().toISOString().slice(0, 10)
    }}
];
msg._mappingId  = d.mappingId;
msg._nsPreserve = Array.isArray(d.namespacesToPreserve) ? d.namespacesToPreserve : [];
msg._shaclId    = d.shaclShapeSchemaId || '';
return [msg, null];

msg.response = {
    action: 'saveRdfMappingConfig',
    success: true,
    mappingId: msg._mappingId,
    namespacesToPreserve: msg._nsPreserve,
    shaclShapeSchemaId: msg._shaclId
};
delete msg._mappingId;
delete msg._nsPreserve;
delete msg._shaclId;
delete msg.payload;
delete msg.collection;
delete msg.operation;
return msg;

const d = msg.data || {};
const rdfInput = d.rdfInput || '';
const format = d.rdfFormat || 'turtle';
const namespacesToPreserve = Array.isArray(d.namespacesToPreserve) ? d.namespacesToPreserve : [];

// ── Step 1: Parse RDF into triples ──
const triples = [];

try {
    const lines = rdfInput.split('\n');
    const prefixes = {};

    for (let line of lines) {
        line = line.trim();
        if (!line || line.startsWith('#')) continue;

        // @prefix declarations
        if (line.startsWith('@prefix') || line.toUpperCase().startsWith('PREFIX')) {
            const m = line.match(/(?:@prefix|PREFIX)\s+(\w*):?\s+<([^>]+)>/i);
            if (m) prefixes[m[1]] = m[2];
            continue;
        }

        // N-Triples: <s> <p> <o> .
        const ntMatch = line.match(/^<([^>]+)>\s+<([^>]+)>\s+(.*)\s*\.$/);
        if (ntMatch) {
            triples.push({ subject: ntMatch[1], predicate: ntMatch[2], object: ntMatch[3].trim() });
            continue;
        }

        // Turtle with prefixes
        const parts = line.replace(/\s*\.\s*$/, '').split(/\s+/);
        if (parts.length >= 3) {
            const expandPrefix = (term) => {
                if (term.startsWith('<') && term.endsWith('>')) return term.slice(1, -1);
                const colonIdx = term.indexOf(':');
                if (colonIdx > -1) {
                    const pre = term.substring(0, colonIdx);
                    const local = term.substring(colonIdx + 1);
                    if (prefixes[pre]) return prefixes[pre] + local;
                }
                return term;
            };
            triples.push({
                subject: expandPrefix(parts[0]),
                predicate: expandPrefix(parts[1]),
                object: parts.slice(2).join(' ')
            });
        }
    }

    if (triples.length === 0) {
        throw new Error('No triples could be parsed from the input. Check the RDF format.');
    }

    // ── Steps 2 + 3: Filter triples by namespace ──
    const retained = [];
    const discarded = [];
    for (const triple of triples) {
        const pred = triple.predicate;
        const inNamespace = namespacesToPreserve.some(ns => pred.startsWith(ns));
        if (inNamespace) retained.push(triple); else discarded.push(triple);
    }

    // ── Step 4: Format output as N-Triples ──
    const outputLines = retained.map(t => {
        const obj = (t.object.startsWith('<') || t.object.startsWith('"')) ? t.object : ('"' + t.object + '"');
        return '<' + t.subject + '> <' + t.predicate + '> ' + obj + ' .';
    });

    // ── Step 5: SHACL Validation (basic structural check) ──
    let shaclResult = null;
    if (d.shaclShapeSchemaId) {
        shaclResult = {
            valid: retained.length > 0,
            errors: retained.length === 0 ? ['No triples retained — output is empty'] : []
        };
    }

    msg.response = {
        action: 'testRdfMapping',
        success: true,
        result: {
            output: outputLines.join('\n'),
            retainedCount: retained.length,
            discardedCount: discarded.length,
            totalTriples: triples.length,
            shaclResult: shaclResult,
            retainedTriples: retained,
            discardedTriples: discarded
        }
    };
} catch (e) {
    msg.response = {
        action: 'testRdfMapping',
        success: false,
        error: e.message
    };
}

return msg;

// FR-SR-12: Provider Selection Precedence
// Priority: prompt.providerId > catalogue.providerId > systemSettings.defaultLlmProviderId
const d = msg._resolveProviderInput || {};
const promptProviderId    = d.promptProviderId || "";
const catalogueProviderId = d.catalogueProviderId || "";
const systemProviderId    = flow.get("defaultLlmProviderId") || "";

let selectedId = "";
let selectedLevel = "none";

if (promptProviderId) {
    selectedId = promptProviderId;
    selectedLevel = "prompt";
} else if (catalogueProviderId) {
    selectedId = catalogueProviderId;
    selectedLevel = "catalogue";
} else if (systemProviderId) {
    selectedId = systemProviderId;
    selectedLevel = "system";
}

if (!selectedId) {
    const legacyKey = flow.get("openai_api_key") || "";
    const legacyModel = flow.get("openai_model") || "gpt-4o";
    if (legacyKey) {
        msg._resolvedProvider = {
            id: "legacy",
            name: "Legacy OpenAI (flow context)",
            type: "openai",
            apiEndpoint: "https://api.openai.com/v1/chat/completions",
            apiKey: legacyKey,
            model: legacyModel,
            timeout: 60,
            level: "legacy"
        };
        return [null, msg];
    }
    msg._resolvedProvider = null;
    msg._providerError = "No provider configured at any level (prompt/catalogue/system).";
    return [null, msg];
}

msg._selectedProviderId = selectedId;
msg._selectedProviderLevel = selectedLevel;
msg.collection = "sr_providers";
msg.operation = "findOne";
msg.payload = { id: selectedId };
return [msg, null];

const provider = Array.isArray(msg.payload) ? msg.payload[0] : msg.payload;
if (!provider) {
    const legacyKey = flow.get("openai_api_key") || "";
    const legacyModel = flow.get("openai_model") || "gpt-4o";
    msg._resolvedProvider = legacyKey ? {
        id: "legacy", name: "Legacy OpenAI", type: "openai",
        apiEndpoint: "https://api.openai.com/v1/chat/completions",
        apiKey: legacyKey, model: legacyModel, timeout: 60, level: "legacy-fallback"
    } : null;
    if (!msg._resolvedProvider) {
        msg._providerError = "Provider " + msg._selectedProviderId + " not found and no legacy key configured.";
    }
} else {
    let apiKey = "";
    if (provider.apiKey && typeof provider.apiKey === 'object' && provider.apiKey.ct) {
        const kmsKey = env.get('DCM_KMS_KEY') || global.get('DCM_KMS_KEY') || '';
        if (kmsKey) {
            try {
                const key = Buffer.from(kmsKey, 'hex');
                const iv = Buffer.from(provider.apiKey.iv, 'hex');
                const tag = Buffer.from(provider.apiKey.tag, 'hex');
                const decipher = crypto.createDecipheriv('aes-256-gcm', key, iv);
                decipher.setAuthTag(tag);
                apiKey = decipher.update(provider.apiKey.ct, 'hex', 'utf8') + decipher.final('utf8');
            } catch(e) { apiKey = ""; }
        }
    } else if (typeof provider.apiKey === 'string') {
        apiKey = provider.apiKey;
    }

    let endpoint = provider.apiEndpoint || "";
    if (!endpoint) {
        if (provider.type === 'openai') endpoint = "https://api.openai.com/v1/chat/completions";
        else if (provider.type === 'anthropic') endpoint = "https://api.anthropic.com/v1/messages";
        else if (provider.type === 'ollama') endpoint = "http://localhost:11434/api/chat";
    }

    msg._resolvedProvider = {
        id: provider.id,
        name: provider.name || "",
        type: provider.type || "openai",
        apiEndpoint: endpoint,
        apiKey: apiKey,
        model: (provider.models && provider.models[0]) || flow.get("openai_model") || "gpt-4o",
        timeout: provider.timeout || 60,
        rateLimits: provider.rateLimits || "",
        level: msg._selectedProviderLevel
    };
}

delete msg._selectedProviderId;
delete msg._selectedProviderLevel;
delete msg.payload;
delete msg.collection;
delete msg.operation;
return msg;

const mappingId = (msg.data && msg.data.mappingId) || (msg.payload && msg.payload.mappingId);
msg._hybrid = {
    mappingId: mappingId,
    inputData: (msg.data && msg.data.inputData) || (msg.payload && msg.payload.inputData),
    phase: 'deterministic',
    startedAt: new Date().toISOString()
};
msg.collection = 'sr_mappings';
msg.operation = 'findOne';
msg.payload = { id: mappingId };
return msg;

const mapping = Array.isArray(msg.payload) ? msg.payload[0] : msg.payload;
if (!mapping) {
    msg.payload = { action: 'executeHybridTransform', ok: false, error: 'Mapping not found' };
    return [null, msg];
}

msg._hybrid.mapping = mapping;
const input = msg._hybrid.inputData;
const namespaces = mapping.namespacesToPreserve || [];

let deterministicResult = { success: false, retainedCount: 0, totalTriples: 0, output: '' };

try {
    const lines = (input || '').split('\n').filter(l => l.trim() && !l.trim().startsWith('@prefix') && !l.trim().startsWith('#'));
    const prefixes = {};
    (input || '').split('\n').forEach(l => {
        const m = l.match(/^@prefix\s+(\w*):?\s+<([^>]+)>/);
        if (m) prefixes[m[1] || ''] = m[2];
    });

    const expandUri = (uri) => {
        if (uri.startsWith('<') && uri.endsWith('>')) return uri.slice(1, -1);
        const parts = uri.split(':');
        if (parts.length === 2 && prefixes[parts[0]] !== undefined) {
            return prefixes[parts[0]] + parts[1];
        }
        return uri;
    };

    const triples = [];
    lines.forEach(line => {
        const cleaned = line.replace(/\s*\.\s*$/, '').trim();
        const parts = cleaned.match(/^(\S+)\s+(\S+)\s+(.+)$/);
        if (parts) {
            triples.push({
                subject: expandUri(parts[1]),
                predicate: expandUri(parts[2]),
                object: parts[3].trim()
            });
        }
    });

    let retained, discarded;
    if (namespaces.length > 0) {
        retained = triples.filter(t => namespaces.some(ns => t.predicate.startsWith(ns) || t.subject.startsWith(ns)));
        discarded = triples.filter(t => !namespaces.some(ns => t.predicate.startsWith(ns) || t.subject.startsWith(ns)));
    } else {
        retained = triples;
        discarded = [];
    }

    const output = retained.map(t => '<' + t.subject + '> <' + t.predicate + '> ' + t.object + ' .').join('\n');

    deterministicResult = {
        success: true,
        retainedCount: retained.length,
        discardedCount: discarded.length,
        totalTriples: triples.length,
        output: output
    };
} catch (err) {
    deterministicResult = { success: false, error: err.message, retainedCount: 0, totalTriples: 0 };
}

msg._hybrid.deterministicResult = deterministicResult;

const minRetainedRatio = 0.3;
const hasOutput = deterministicResult.success && deterministicResult.retainedCount > 0;
const ratioOk = deterministicResult.totalTriples > 0
    ? (deterministicResult.retainedCount / deterministicResult.totalTriples) >= minRetainedRatio
    : false;

if (hasOutput && ratioOk) {
    msg._hybrid.phase = 'deterministic_success';
    msg._hybrid.completedAt = new Date().toISOString();
    msg.payload = {
        action: 'executeHybridTransform',
        ok: true,
        phase: 'deterministic',
        fallbackTriggered: false,
        result: deterministicResult
    };
    return [null, msg];
} else {
    msg._hybrid.phase = 'ai_fallback';
    msg._hybrid.deterministicFailReason = !deterministicResult.success
        ? 'parse_error: ' + (deterministicResult.error || 'unknown')
        : 'low_retention: ' + deterministicResult.retainedCount + '/' + deterministicResult.totalTriples + ' (' + Math.round((deterministicResult.retainedCount / Math.max(deterministicResult.totalTriples, 1)) * 100) + '%)';
    return [msg, null];
}

const mapping = msg._hybrid.mapping;
msg.collection = 'sr_prompts';
msg.operation = 'findOne';
msg.payload = {
    sourceSchema: mapping.remoteSchema || mapping.remoteCatalogue,
    status: 'active'
};
return msg;

const prompt = Array.isArray(msg.payload) ? msg.payload[0] : msg.payload;
const mapping = msg._hybrid.mapping;
const inputData = msg._hybrid.inputData;

if (!prompt) {
    msg._hybrid.completedAt = new Date().toISOString();
    msg.payload = {
        action: 'executeHybridTransform',
        ok: false,
        phase: 'ai_fallback',
        fallbackTriggered: true,
        fallbackReason: msg._hybrid.deterministicFailReason,
        error: 'No active prompt found for this mapping source schema'
    };
    return [null, msg];
}

let template = prompt.template || '';
template = template.replace(/\{SOURCE_ASSET\}/g, inputData || '');
template = template.replace(/\{SOURCE_SCHEMA\}/g, prompt.sourceSchema || '');
template = template.replace(/\{TARGET_SCHEMA\}/g, prompt.targetSchema || '');
template = template.replace(/\{EXAMPLES\}/g, prompt.examples || '');
template = template.replace(/\{CONSTRAINTS\}/g, prompt.constraints || '');

const providerId = prompt.providerId || mapping.providerId || null;

msg._hybrid.promptId = prompt.id;
msg._hybrid.promptVersion = prompt.version;
msg._hybrid.resolvedTemplate = template;
msg._hybrid.providerId = providerId;

if (providerId) {
    msg.collection = 'sr_providers';
    msg.operation = 'findOne';
    msg.payload = { id: providerId };
    return [msg, null];
} else {
    const apiKey = flow.get('openai_api_key') || '';
    msg._hybrid.providerConfig = {
        type: 'openai',
        model: 'gpt-4',
        apiKey: apiKey,
        baseUrl: 'https://api.openai.com/v1/chat/completions'
    };
    return [null, msg];
}

let providerConfig = msg._hybrid.providerConfig;
if (!providerConfig && msg.payload) {
    const provider = Array.isArray(msg.payload) ? msg.payload[0] : msg.payload;
    let apiKey = '';
    if (provider && provider.apiKeyEncrypted) {
        try {
            const enc = typeof provider.apiKeyEncrypted === 'string' ? JSON.parse(provider.apiKeyEncrypted) : provider.apiKeyEncrypted;
            const SECRET = flow.get('provider_encryption_key') || flow.get('openai_api_key') || '';
            const key = crypto.createHash('sha256').update(SECRET).digest();
            const decipher = crypto.createDecipheriv('aes-256-gcm', key, Buffer.from(enc.iv, 'hex'));
            decipher.setAuthTag(Buffer.from(enc.tag, 'hex'));
            apiKey = decipher.update(enc.data, 'hex', 'utf8') + decipher.final('utf8');
        } catch (e) {
            apiKey = flow.get('openai_api_key') || '';
        }
    } else if (provider && provider.apiKey && typeof provider.apiKey === 'object' && provider.apiKey.ct) {
        const kmsKey = env.get('DCM_KMS_KEY') || global.get('DCM_KMS_KEY') || '';
        if (kmsKey) {
            try {
                const key = Buffer.from(kmsKey, 'hex');
                const iv = Buffer.from(provider.apiKey.iv, 'hex');
                const tag = Buffer.from(provider.apiKey.tag, 'hex');
                const decipher = crypto.createDecipheriv('aes-256-gcm', key, iv);
                decipher.setAuthTag(tag);
                apiKey = decipher.update(provider.apiKey.ct, 'hex', 'utf8') + decipher.final('utf8');
            } catch (e) { apiKey = ''; }
        }
    } else if (provider && typeof provider.apiKey === 'string') {
        apiKey = provider.apiKey;
    } else {
        apiKey = flow.get('openai_api_key') || '';
    }
    providerConfig = {
        type: (provider && provider.type) || 'openai',
        model: (provider && (provider.model || (provider.models && provider.models[0]))) || 'gpt-4',
        apiKey: apiKey,
        baseUrl: (provider && (provider.baseUrl || provider.apiEndpoint)) || 'https://api.openai.com/v1/chat/completions',
        customHeaders: (provider && provider.customHeaders) || {}
    };
}

const template = msg._hybrid.resolvedTemplate;

msg.url = providerConfig.baseUrl;
msg.method = 'POST';
msg.headers = Object.assign({
    'Content-Type': 'application/json',
    'Authorization': 'Bearer ' + providerConfig.apiKey
}, providerConfig.customHeaders || {});
msg.payload = {
    model: providerConfig.model,
    messages: [
        { role: 'system', content: 'You are a data transformation expert. Generate a JavaScript function that transforms the source data to match the target schema.' },
        { role: 'user', content: template }
    ],
    temperature: 0.2,
    max_tokens: 4000
};

return msg;

let aiResult = { success: false, output: '' };

try {
    const body = typeof msg.payload === 'string' ? JSON.parse(msg.payload) : msg.payload;
    const content = body && body.choices && body.choices[0] && body.choices[0].message
        ? body.choices[0].message.content
        : '';

    if (content) {
        aiResult = {
            success: true,
            output: content,
            model: body.model || '',
            tokensUsed: body.usage ? body.usage.total_tokens : 0
        };
    } else {
        aiResult = { success: false, error: 'Empty LLM response' };
    }
} catch (err) {
    aiResult = { success: false, error: 'LLM response parse error: ' + err.message };
}

msg._hybrid.completedAt = new Date().toISOString();

msg.payload = {
    action: 'executeHybridTransform',
    ok: aiResult.success,
    phase: 'ai_fallback',
    fallbackTriggered: true,
    fallbackReason: msg._hybrid.deterministicFailReason,
    deterministicResult: {
        retainedCount: msg._hybrid.deterministicResult.retainedCount,
        totalTriples: msg._hybrid.deterministicResult.totalTriples,
        success: msg._hybrid.deterministicResult.success
    },
    aiResult: aiResult,
    promptId: msg._hybrid.promptId,
    promptVersion: msg._hybrid.promptVersion,
    timing: {
        startedAt: msg._hybrid.startedAt,
        completedAt: msg._hybrid.completedAt
    }
};

return msg;

const h = msg._hybrid || {};
const result = msg.payload || {};

const auditRecord = {
    transformationId: 'txn-' + Date.now() + '-' + Math.random().toString(36).substr(2, 6),
    mappingId: h.mappingId,
    strategy: 'Hybrid',
    phase: result.phase,
    fallbackTriggered: result.fallbackTriggered || false,
    fallbackReason: result.fallbackReason || null,
    deterministicRetained: h.deterministicResult ? h.deterministicResult.retainedCount : 0,
    deterministicTotal: h.deterministicResult ? h.deterministicResult.totalTriples : 0,
    aiModel: result.aiResult ? result.aiResult.model : null,
    promptId: h.promptId || null,
    promptVersion: h.promptVersion || null,
    status: result.ok ? 'completed' : 'failed',
    error: result.error || null,
    startedAt: h.startedAt,
    completedAt: h.completedAt || new Date().toISOString(),
    createdAt: new Date().toISOString()
};

const auditMsg = {
    collection: 'dcm_transformation_audit',
    operation: 'insertOne',
    payload: auditRecord,
    _msgid: msg._msgid
};

node.send([msg, auditMsg]);
return null;

const now = new Date().toISOString();
const doc = {
    uniqueId: 'prompt_api_mapping_default',
    id: 'prompt_api_mapping_default',
    name: 'Default API Mapping Prompt',
    version: 'v1',
    kind: 'api-mapping',
    status: 'active',
    targetCatalogueId: '',
    sourceSchema: '',
    targetSchema: '',
    template: 'You are an API mapping assistant. Given the local asset type and target remote catalogue, produce an HTTP API request spec that will retrieve assets of that type from the remote catalogue.\n\nLocal asset type: {local_type_name}\nLocal asset type description: {local_type_description}\nTarget remote catalogue: {catalogue_name}\nRemote catalogue base endpoint: {catalogue_endpoint}\nRemote catalogue interface type: {catalogue_interface_type}\nRemote asset type (if known): {remote_type}\nAuth info: {catalogue_auth}\n\nReturn ONLY a JSON object:\n{\n  "method": "GET|POST|PUT|DELETE",\n  "pathTemplate": "/relative/path",\n  "queryParams": { "key": "value" },\n  "headers": { "Accept": "application/json" },\n  "bodyTemplate": null,\n  "notes": "Short rationale"\n}\n\nNo markdown fencing, no explanations outside JSON.',
    templateText: '',
    examples: '',
    constraints: '',
    providerId: '',
    originalPrompt: '',
    enhancedPrompt: '',
    generatedCode: '',
    codeGenerationStatus: 'n/a',
    createdAt: now,
    updatedAt: now
};
doc.templateText = doc.template;
msg.collection = 'sr_prompts';
msg.operation  = 'updateOne';
msg.payload    = [{ uniqueId: doc.uniqueId }, { $setOnInsert: doc }, { upsert: true }];
return msg;

// FR-CR-03 generic LLM caller (honours msg._llmForceJson for OpenAI response_format)
const req = msg._llmRequest || { system: '', user: '' };
const rp = msg._resolvedProvider || {};
const apiKey = rp.apiKey || flow.get('openai_api_key') || '';
const model  = rp.model || flow.get('openai_model') || 'gpt-4o';
if (!apiKey) {
    msg._llmRawResponse = '';
    msg._llmError = 'No LLM API key configured';
    return [null, msg];
}
msg.url = rp.apiEndpoint || 'https://api.openai.com/v1/chat/completions';
if (rp.type === 'anthropic') {
    msg.headers = { 'Content-Type': 'application/json', 'x-api-key': apiKey, 'anthropic-version': '2023-06-01' };
    msg.payload = { model: model, max_tokens: 2048, system: req.system || '', messages: [{ role: 'user', content: req.user || '' }] };
} else {
    msg.headers = { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + apiKey };
    const body = {
        model: model,
        temperature: 0.2,
        max_tokens: 2048,
        messages: [
            { role: 'system', content: req.system || '' },
            { role: 'user',   content: req.user   || '' }
        ]
    };
    // When the caller flag msg._llmForceJson is true, ask OpenAI for a strict JSON object.
    if (msg._llmForceJson === true) {
        body.response_format = { type: 'json_object' };
    }
    msg.payload = body;
}
return [msg, null];

// Generic LLM: extract text (FIX: surface HTTP error bodies so callers don't see misleading "non-JSON response")
const body = msg.payload || {};
const statusCode = msg.statusCode || 0;

// If HTTP wasn't 2xx OR body has an error object, propagate a real error instead of silently emptying text.
if ((statusCode && (statusCode < 200 || statusCode >= 300)) || (body && body.error)) {
    const errMsg = (body && body.error && body.error.message) || JSON.stringify(body || {}).slice(0, 500);
    const errCode = (body && body.error && body.error.code) || (body && body.error && body.error.type) || ('http_' + statusCode);
    msg._llmError = 'LLM API error (' + errCode + '): ' + errMsg;
    msg._llmRawResponse = '';
    node.warn('Generic LLM error: status=' + statusCode + ' code=' + errCode + ' msg=' + errMsg);
    delete msg.payload;
    return msg;
}

let text = '';
try {
    if (body.choices && body.choices[0] && body.choices[0].message) {
        text = body.choices[0].message.content || '';
    } else if (Array.isArray(body.content) && body.content[0]) {
        text = body.content[0].text || '';
    } else if (typeof body === 'string') {
        text = body;
    }
} catch (e) { text = ''; }
msg._llmRawResponse = text;
delete msg.payload;
return msg;

const d = msg.data || {};
msg._enhProviderCandidateId = d.providerId || '';
msg.collection = 'sr_providers';
msg.operation  = 'find';
msg.payload    = [{ status: 'active' }, { projection: { _id: 0 }, sort: { isDefault: -1, precedence: 1 } }];
return msg;

const providers = Array.isArray(msg.payload) ? msg.payload : [];
const pickId = msg._enhProviderCandidateId || '';
let chosen = null;
if (pickId) chosen = providers.find(p => p.id === pickId) || null;
if (!chosen) chosen = providers.find(p => p.isDefault) || providers[0] || null;

let apiKey = '';
if (chosen && chosen.apiKey) {
    if (typeof chosen.apiKey === 'object' && chosen.apiKey.ct) {
        const kmsKey = env.get('DCM_KMS_KEY') || global.get('DCM_KMS_KEY') || '';
        if (kmsKey) {
            try {
                const key = Buffer.from(kmsKey, 'hex');
                const iv  = Buffer.from(chosen.apiKey.iv, 'hex');
                const tag = Buffer.from(chosen.apiKey.tag, 'hex');
                const decipher = crypto.createDecipheriv('aes-256-gcm', key, iv);
                decipher.setAuthTag(tag);
                apiKey = decipher.update(chosen.apiKey.ct, 'hex', 'utf8') + decipher.final('utf8');
            } catch (e) { apiKey = ''; node.warn('enhancePrompt provider decrypt failed: ' + e.message); }
        }
    } else if (typeof chosen.apiKey === 'string') {
        apiKey = chosen.apiKey;
    }
}
if (!apiKey) apiKey = flow.get('openai_api_key') || '';

let endpoint = (chosen && chosen.apiEndpoint) || '';
if (!endpoint && chosen) {
    if (chosen.type === 'anthropic') endpoint = 'https://api.anthropic.com/v1/messages';
    else if (chosen.type === 'ollama') endpoint = 'http://localhost:11434/api/chat';
    else endpoint = 'https://api.openai.com/v1/chat/completions';
}
if (!endpoint) endpoint = 'https://api.openai.com/v1/chat/completions';

msg._resolvedProvider = {
    id: (chosen && chosen.id) || 'legacy',
    name: (chosen && chosen.name) || 'Legacy OpenAI (flow.context)',
    type: (chosen && chosen.type) || 'openai',
    apiEndpoint: endpoint,
    apiKey: apiKey,
    model: (chosen && chosen.models && chosen.models.length > 0 && chosen.models[0]) || (chosen && chosen.defaultModel) || flow.get('openai_model') || env.get('OPENAI_MODEL') || 'gpt-3.5-turbo',
    timeout: (chosen && chosen.timeout) || 60
};

delete msg.payload; delete msg.collection; delete msg.operation; delete msg._enhProviderCandidateId;
return msg;

msg._apiMapProviderCandidateId = (msg._promptData && msg._promptData.providerId) || '';
msg.collection = 'sr_providers';
msg.operation  = 'find';
msg.payload    = [{ status: 'active' }, { projection: { _id: 0 }, sort: { precedence: 1 } }];
return msg;

